package dev.codedefense.cli;import dev.codedefense.application.*;import dev.codedefense.passport.*;import java.nio.file.Path;import java.util.concurrent.Callable;import picocli.CommandLine.*;
@Command(name="inspect",mixinStandardHelpOptions=true,description="Inspect a handoff without Git or Codex.")public final class PassportHandoffInspectCommand implements Callable<Integer>{@Parameters(index="0")Path input;@Spec Model.CommandSpec spec;private final InspectChangeHandoffUseCase useCase;public PassportHandoffInspectCommand(){this(new InspectChangeHandoffUseCase(new FileSystemChangeHandoffStore(),new ChangeHandoffJsonCodec(),new ChangeHandoffTerminalRenderer()));}PassportHandoffInspectCommand(InspectChangeHandoffUseCase u){useCase=u;}public Integer call(){try{return useCase.inspect(input,spec.commandLine().getOut(),spec.commandLine().getErr());}catch(ChangeHandoffPersistenceException e){spec.commandLine().getErr().println(e.getMessage());return ExitCodes.REPORT_PERSISTENCE_FAILED;}}}
